    fn decrement(&self, amount: i32) {
        let stock = self.stock.clone();
        let handle = thread::spawn(move || {
            *stock.lock().unwrap() -= amount;
            println!("Remaining inventory: {}", *stock.lock().unwrap());
        });
        handle.join().expect("Failed to join thread");
    }
